import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  TextField,
  Button,
  FormControlLabel,
  Switch,
  Typography,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  Alert,
  Snackbar
} from '@mui/material';
import { getSettings, updateSettings } from '../services/api';

const Settings = () => {
  const [settings, setSettings] = useState({
    network: {
      theme: 'auto',
      password: '',
      confirmPassword: '',
      port: 2345
    },
    dns: {
      mainIP: '10.0.0.1',
      dnsType: 'IPV4',
      usePTConnection: false
    },
    proxy: {
      proxyName: 'Proxy'
    }
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      setLoading(true);
      const data = await getSettings();
      setSettings(data);
    } catch (err) {
      setError('Failed to load settings');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (section, field) => (event) => {
    setSettings(prev => ({
      ...prev,
      [section]: {
        ...prev[section],
        [field]: event.target.type === 'checkbox' ? event.target.checked : event.target.value
      }
    }));
  };

  const handleSubmit = async (section) => {
    try {
      setLoading(true);
      await updateSettings({ [section]: settings[section] });
      setSuccess(true);
    } catch (err) {
      setError('Failed to update settings');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">Settings updated successfully</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Grid container spacing={3}>
        {/* Network Settings */}
        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>网络设置</Typography>
              <Grid container spacing={2}>
                <Grid item xs={12} md={6}>
                  <FormControl fullWidth>
                    <InputLabel>主题</InputLabel>
                    <Select
                      value={settings.network.theme}
                      onChange={handleChange('network', 'theme')}
                      label="主题"
                    >
                      <MenuItem value="auto">自动</MenuItem>
                      <MenuItem value="light">亮色</MenuItem>
                      <MenuItem value="dark">暗色</MenuItem>
                    </Select>
                  </FormControl>
                </Grid>
                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="修改密码"
                    type="password"
                    value={settings.network.password}
                    onChange={handleChange('network', 'password')}
                  />
                </Grid>
                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="确认密码"
                    type="password"
                    value={settings.network.confirmPassword}
                    onChange={handleChange('network', 'confirmPassword')}
                  />
                </Grid>
                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="回源端口"
                    type="number"
                    value={settings.network.port}
                    onChange={handleChange('network', 'port')}
                  />
                </Grid>
                <Grid item xs={12}>
                  <Button 
                    variant="contained" 
                    onClick={() => handleSubmit('network')}
                    disabled={loading}
                  >
                    保存
                  </Button>
                </Grid>
              </Grid>
            </CardContent>
          </Card>
        </Grid>

        {/* DNS Settings */}
        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>DNS设置</Typography>
              <Grid container spacing={2}>
                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="主服IP"
                    value={settings.dns.mainIP}
                    onChange={handleChange('dns', 'mainIP')}
                  />
                </Grid>
                <Grid item xs={12} md={6}>
                  <FormControl fullWidth>
                    <InputLabel>DNS类型</InputLabel>
                    <Select
                      value={settings.dns.dnsType}
                      onChange={handleChange('dns', 'dnsType')}
                      label="DNS类型"
                    >
                      <MenuItem value="IPV4">仅IPV4</MenuItem>
                      <MenuItem value="IPV6">仅IPV6</MenuItem>
                      <MenuItem value="BOTH">IPV4+IPV6</MenuItem>
                    </Select>
                  </FormControl>
                </Grid>
                <Grid item xs={12}>
                  <FormControlLabel
                    control={
                      <Switch
                        checked={settings.dns.usePTConnection}
                        onChange={handleChange('dns', 'usePTConnection')}
                      />
                    }
                    label="启用PT直连"
                  />
                </Grid>
                <Grid item xs={12}>
                  <Button 
                    variant="contained" 
                    onClick={() => handleSubmit('dns')}
                    disabled={loading}
                  >
                    保存
                  </Button>
                </Grid>
              </Grid>
            </CardContent>
          </Card>
        </Grid>

        {/* Proxy Settings */}
        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>通用配置</Typography>
              <Grid container spacing={2}>
                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="通用规则名称"
                    value={settings.proxy.proxyName}
                    onChange={handleChange('proxy', 'proxyName')}
                  />
                </Grid>
                <Grid item xs={12}>
                  <Button 
                    variant="contained" 
                    onClick={() => handleSubmit('proxy')}
                    disabled={loading}
                  >
                    保存
                  </Button>
                </Grid>
              </Grid>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default Settings;
